   1→import supabase from "./supabase.js";
   2→import GenerateEmbeddings from "../utils/GenerateEmbeddings.js";
   3→
   4→const SEARCH_LIMIT_MAX = 20;
   5→const SEARCH_QUERY_MIN_LENGTH = 2;
   6→const CANVAS_GALLERY_LIMIT_DEFAULT = 36;
   7→const CANVAS_GALLERY_LIMIT_MAX = 72;
   8→const CANVAS_GALLERY_HOT_FETCH_LIMIT = 220;
   9→const UNIVERSE_POST_LIMIT_DEFAULT = 200;
  10→const UNIVERSE_POST_LIMIT_MAX = 500;
  11→const UNIVERSE_SIMILARITY_THRESHOLD = 0.9;
  12→const UNIVERSE_SIMILARITY_PAIR_LIMIT = 120;
  13→const UNIVERSE_STAR_PULL_MIN_SIMILARITY = 0.4;
  14→const UNIVERSE_STAR_PULL_LIMIT = 500;
  15→const UNIVERSE_POST_SELECT = `
  16→    id,
  17→    title,
  18→    content,
  19→    post_type,
  20→    canvas_doc,
  21→    created_at,
  22→    universe_x,
  23→    universe_y,
  24→    settled_x,
  25→    settled_y,
  26→    user_id,
  27→    users(id, name, image_url, badge),
  28→    likes(count)
  29→`;
  30→const PROFILE_MEDIA_BUCKETS = ['background', 'journal-images', 'avatars'];
  31→const PROFILE_MEDIA_EXTENSIONS = ['.jpg', '.jpeg', '.png', '.webp', '.gif', '.bmp', '.avif', '.svg'];
  32→const PROFILE_MEDIA_LIMIT_DEFAULT = 5;
  33→const PROFILE_MEDIA_LIMIT_MAX = 20;
