  35→const attachRepostSources = async (journals) => {
  36→    const items = Array.isArray(journals) ? journals : [journals];
  37→    const sourceIds = [...new Set(
  38→        items
  39→            .filter(j => j.is_repost === true && j.repost_source_journal_id != null)
  40→            .map(j => j.repost_source_journal_id)
  41→    )];
  42→
  43→    if (sourceIds.length === 0) {
  44→        items.forEach(j => { j.repost_source = null; });
  45→        return journals;
  46→    }
  47→
  48→    const { data: sources, error } = await supabase
  49→        .from('journals')
  50→        .select('id, title, content, post_type, canvas_doc, created_at, users(id, name, image_url, badge)')
  51→        .in('id', sourceIds);
  52→
  53→    if (error) {
  54→        console.error('supabase error fetching repost sources:', error.message);
  55→        items.forEach(j => { j.repost_source = null; });
  56→        return journals;
  57→    }
  58→
  59→    const sourceMap = new Map(sources.map(s => [s.id, s]));
  60→    items.forEach(j => {
  61→        j.repost_source = j.repost_source_journal_id
  62→            ? (sourceMap.get(j.repost_source_journal_id) || null)
  63→            : null;
  64→    });
  65→
  66→    return journals;
  67→};
  68→
  69→const parseFiniteNumber = (value, fieldName) => {
  70→    const parsed = Number(value);
  71→    if(!Number.isFinite(parsed)){
  72→        throw {status: 400, error: `${fieldName} should be a finite number`};
  73→    }
  74→    return parsed;
  75→};
  76→
  77→const normalizeUniversePost = (post = {}) => {
  78→    const likes = Array.isArray(post?.likes) ? post.likes : [];
  79→    const likeCount = post?.like_count != null
  80→        ? Number(post.like_count)
  81→        : Number(likes?.[0]?.count ?? 0);
  82→
  83→    return {
  84→        ...post,
  85→        user_id: post?.user_id ?? post?.users?.id ?? null,
  86→        user_name: post?.user_name ?? post?.users?.name ?? null,
  87→        user_image_url: post?.user_image_url ?? post?.users?.image_url ?? null,
  88→        user_badge: post?.user_badge ?? post?.users?.badge ?? null,
  89→        display_x: post?.display_x ?? post?.settled_x ?? post?.universe_x ?? null,
  90→        display_y: post?.display_y ?? post?.settled_y ?? post?.universe_y ?? null,
  91→        like_count: Number.isFinite(likeCount) ? likeCount : 0
  92→    };
  93→};
  94→
  95→const loadUniversePostsViaRpc = async(minX, maxX, minY, maxY, limit) => {
  96→    const {data, error} = await supabase.rpc('get_universe_posts_viewport', {
  97→        vp_min_x: minX,
  98→        vp_max_x: maxX,
  99→        vp_min_y: minY,
 100→        vp_max_y: maxY,
 101→        max_count: limit
 102→    });
 103→
 104→    if(error){
 105→        throw error;
 106→    }
 107→
 108→    return Array.isArray(data) ? data.map(normalizeUniversePost) : [];
 109→};
 110→
 111→const loadUniversePostsFallback = async(minX, maxX, minY, maxY, limit) => {
 112→    const settledQuery = supabase
 113→        .from('journals')
 114→        .select(UNIVERSE_POST_SELECT)
 115→        .eq('privacy', 'public')
 116→        .not('settled_x', 'is', null)
 117→        .not('settled_y', 'is', null)
 118→        .gte('settled_x', minX)
 119→        .lte('settled_x', maxX)
 120→        .gte('settled_y', minY)
 121→        .lte('settled_y', maxY)
 122→        .order('created_at', {ascending: false})
 123→        .limit(limit);
 124→
 125→    const unsettledQuery = supabase
 126→        .from('journals')
 127→        .select(UNIVERSE_POST_SELECT)
 128→        .eq('privacy', 'public')
 129→        .is('settled_x', null)
 130→        .is('settled_y', null)
 131→        .gte('universe_x', minX)
 132→        .lte('universe_x', maxX)
 133→        .gte('universe_y', minY)
 134→        .lte('universe_y', maxY)
 135→        .order('created_at', {ascending: false})
 136→        .limit(limit);
 137→
 138→    const [
 139→        {data: settledData, error: settledError},
 140→        {data: unsettledData, error: unsettledError}
 141→    ] = await Promise.all([settledQuery, unsettledQuery]);
 142→
 143→    if(settledError || unsettledError){
 144→        console.error(
 145→            'supabase fallback error while fetching universe posts:',
 146→            settledError?.message || unsettledError?.message
 147→        );
 148→        throw {status: 500, error: 'failed to fetch universe posts'};
 149→    }
 150→
 151→    const mergedById = new Map();
 152→    const mergedRows = [...(settledData || []), ...(unsettledData || [])];
 153→    for (const row of mergedRows) {
 154→        if(!row?.id || mergedById.has(row.id)){
 155→            continue;
 156→        }
 157→
 158→        mergedById.set(row.id, normalizeUniversePost(row));
 159→        if(mergedById.size >= limit){
 160→            break;
 161→        }
 162→    }
 163→
 164→    return Array.from(mergedById.values());
 165→};
