 167→const getUniverseCentroids = async(userIds) => {
 168→    if(!Array.isArray(userIds) || userIds.length === 0){
 169→        return [];
 170→    }
 171→
 172→    const {data, error} = await supabase
 173→        .from('galaxy_centroids')
 174→        .select('user_id, galaxy_x, galaxy_y, mean_embedding')
 175→        .in('user_id', userIds);
 176→
 177→    if(error){
 178→        console.warn('supabase warning while fetching universe centroids:', error.message);
 179→        return [];
 180→    }
 181→
 182→    return Array.isArray(data) ? data : [];
 183→};
