 185→const getUniverseEdges = async(userIds) => {
 186→    if(!Array.isArray(userIds) || userIds.length < 2){
 187→        return [];
 188→    }
 189→
 190→    const {data, error} = await supabase
 191→        .from('galaxy_edges')
 192→        .select('user_a, user_b, similarity')
 193→        .in('user_a', userIds)
 194→        .in('user_b', userIds);
 195→
 196→    if(error){
 197→        console.warn('supabase warning while fetching universe edges:', error.message);
 198→        return [];
 199→    }
 200→
 201→    return Array.isArray(data) ? data : [];
