 204→const getUniverseSimilarPairs = async(postIds) => {
 205→    if(!Array.isArray(postIds) || postIds.length < 2){
 206→        return [];
 207→    }
 208→
 209→    const {data, error} = await supabase.rpc('find_similar_post_pairs', {
 210→        post_ids: postIds,
 211→        threshold: UNIVERSE_SIMILARITY_THRESHOLD,
 212→        max_pairs: UNIVERSE_SIMILARITY_PAIR_LIMIT
 213→    });
 214→
 215→    if(error){
 216→        console.warn('supabase warning while fetching similar universe post pairs:', error.message);
 217→        return [];
 218→    }
 219→
 220→    return Array.isArray(data) ? data : [];
