 223→const getUniverseStarPulls = async(postIds) => {
 224→    if(!Array.isArray(postIds) || postIds.length === 0){
 225→        return [];
 226→    }
 227→
 228→    const {data, error} = await supabase.rpc('get_star_galaxy_pulls', {
