 252→const attachUserInteractionFlags = async (journals, userId) => {
 253→    if(!Array.isArray(journals) || journals.length === 0){
 254→        return [];
 255→    }
 256→
 257→    if(!userId){
 258→        return journals.map((journal) => ({
 259→            ...journal,
 260→            has_liked: false,
 261→            has_bookmarked: false
 262→        }));
 263→    }
 264→
 265→    const journalIds = journals.map((journal) => journal.id);
 266→
 267→    const [userLikes, userBookmarks] = await Promise.all([
 268→        supabase
 269→            .from('likes')
 270→            .select('journal_id')
 271→            .in('journal_id', journalIds)
 272→            .eq('user_id', userId),
 273→        supabase
 274→            .from('bookmarks')
 275→            .select('journal_id')
 276→            .in('journal_id', journalIds)
 277→            .eq('user_id', userId)
 278→    ]);
 279→
 280→    const {data: userLikesResult, error: errorUserLikeResult} = userLikes;
