 500→export const getProfileMediaService = async(userId, limit = PROFILE_MEDIA_LIMIT_DEFAULT, cursor = null) => {
 501→    if(!userId){
 502→        throw {status: 400, error: 'userId is undefined'};
 503→    }
 504→
 505→    const parsedLimit = Number(limit);
 506→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > PROFILE_MEDIA_LIMIT_MAX){
 507→        throw {status: 400, error: `limit should be an integer between 1 and ${PROFILE_MEDIA_LIMIT_MAX}`};
 508→    }
 509→
 510→    const cursorState = parseMediaCursor(cursor);
 511→    const offsets = {...cursorState.offsets};
 512→    const exhausted = {...cursorState.exhausted};
 513→    const pending = Array.isArray(cursorState.pending) ? [...cursorState.pending] : [];
 514→    const unavailableBuckets = [];
 515→    const maxIterations = 6;
 516→    let iterationCount = 0;
 517→
 518→    while(
 519→        pending.length < parsedLimit &&
 520→        PROFILE_MEDIA_BUCKETS.some((bucket) => !exhausted[bucket]) &&
 521→        iterationCount < maxIterations
 522→    ){
 523→        iterationCount += 1;
 524→        const activeBuckets = PROFILE_MEDIA_BUCKETS.filter((bucket) => !exhausted[bucket]);
 525→        const chunkResults = await Promise.all(
 526→            activeBuckets.map((bucket) => listMediaChunkForBucket(bucket, userId, offsets[bucket] || 0, parsedLimit))
 527→        );
 528→
 529→        chunkResults.forEach((result) => {
 530→            offsets[result.bucket] = result.nextOffset;
 531→            exhausted[result.bucket] = result.exhausted;
 532→
 533→            if(result.error){
 534→                console.error(`supabase storage list error on ${result.bucket}:`, result.error);
 535→                unavailableBuckets.push(result.bucket);
 536→                return;
 537→            }
 538→
 539→            pending.push(...result.items);
 540→        });
 541→
 542→        if(chunkResults.every((result) => result.items.length === 0)){
 543→            break;
 544→        }
 545→    }
 546→
 547→    pending.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
 548→
 549→    const selectedItems = pending.slice(0, parsedLimit);
 550→    const remainingItems = pending.slice(parsedLimit);
 551→    const hydratedSelectedItems = await hydrateMediaItems(selectedItems);
 552→
 553→    // If a URL cannot be created for some selected items, try to fill from remaining items.
 554→    if(hydratedSelectedItems.length < parsedLimit && remainingItems.length > 0){
 555→        const neededItemsCount = parsedLimit - hydratedSelectedItems.length;
 556→        const fallbackCandidates = remainingItems.splice(0, neededItemsCount);
 557→        const hydratedFallbackItems = await hydrateMediaItems(fallbackCandidates);
 558→        hydratedSelectedItems.push(...hydratedFallbackItems);
 559→    }
 560→
 561→    const hasMore = remainingItems.length > 0 || PROFILE_MEDIA_BUCKETS.some((bucket) => !exhausted[bucket]);
 562→    const dedupedUnavailableBuckets = [...new Set(unavailableBuckets)];
 563→
 564→    const nextCursor = hasMore
 565→        ? encodeMediaCursor({
 566→            offsets: offsets,
 567→            exhausted: exhausted,
 568→            pending: remainingItems
 569→        })
 570→        : null;
 571→
 572→    return {
 573→        data: hydratedSelectedItems,
 574→        hasMore: hasMore,
 575→        nextCursor: nextCursor,
 576→        unavailableBuckets: dedupedUnavailableBuckets
 577→    };
 578→}
