 580→export const getUniversePostsService = async(minX, maxX, minY, maxY, limit = UNIVERSE_POST_LIMIT_DEFAULT) => {
 581→    const parsedMinX = parseFiniteNumber(minX, 'minX');
 582→    const parsedMaxX = parseFiniteNumber(maxX, 'maxX');
 583→    const parsedMinY = parseFiniteNumber(minY, 'minY');
 584→    const parsedMaxY = parseFiniteNumber(maxY, 'maxY');
 585→    const parsedLimit = Number(limit);
 586→
 587→    if(parsedMinX > parsedMaxX){
 588→        throw {status: 400, error: 'minX should be less than or equal to maxX'};
 589→    }
 590→
 591→    if(parsedMinY > parsedMaxY){
 592→        throw {status: 400, error: 'minY should be less than or equal to maxY'};
 593→    }
 594→
 595→    if(!Number.isInteger(parsedLimit) || parsedLimit < 1 || parsedLimit > UNIVERSE_POST_LIMIT_MAX){
 596→        throw {status: 400, error: `limit should be an integer between 1 and ${UNIVERSE_POST_LIMIT_MAX}`};
 597→    }
 598→
 599→    let posts = [];
 600→    let usedFallback = false;
 601→
 602→    try {
 603→        posts = await loadUniversePostsViaRpc(parsedMinX, parsedMaxX, parsedMinY, parsedMaxY, parsedLimit);
 604→    } catch (error) {
 605→        usedFallback = true;
 606→        console.warn('universe viewport RPC unavailable, using fallback query:', error?.message || error);
 607→    }
 608→
 609→    if(usedFallback){
 610→        posts = await loadUniversePostsFallback(parsedMinX, parsedMaxX, parsedMinY, parsedMaxY, parsedLimit);
 611→    }
 612→
 613→    const postIds = Array.from(new Set(posts.map((post) => post?.id).filter(Boolean)));
 614→    const visibleUserIds = Array.from(new Set(
 615→        posts
 616→            .map((post) => post?.users?.id ?? post?.user_id)
 617→            .filter(Boolean)
 618→    ));
 619→
 620→    const [centroids, edges, similarPairs, starPulls] = await Promise.all([
 621→        getUniverseCentroids(visibleUserIds),
 622→        getUniverseEdges(visibleUserIds),
 623→        getUniverseSimilarPairs(postIds),
 624→        getUniverseStarPulls(postIds)
 625→    ]);
 626→
 627→    return {
 628→        data: posts,
 629→        centroids: centroids,
 630→        edges: edges,
 631→        similarPairs: similarPairs,
 632→        starPulls: starPulls
 633→    };
 634→}
