import { useEffect, useRef, useState } from "react";
import { MoonLoader } from "react-spinners";
import { useQuery } from "@tanstack/react-query";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { getMonthlyHottestJournals, searchJournals, searchUsers } from "../../../../API/Api";
import { useAuth } from "../../../Context/useAuth";
import { handleClickProfile } from "../../../../helpers/handleClicks";
import ParseContent from "../postCards/parseData";
import CalculateText from "../postCards/calculateReadingTime";
import formatPostDate from "../../../../helpers/formatDateString";
import VerifiedBadge from "../../Badge/VerifiedBadge";
import { handleImageFallback } from "../../../utils/handleImageFallback";
import { useAddViewsMutation } from "../../../utils/useMutation";
import UserSearchResults from "./UserSearchResults";
import "../postCards/postcards.css";
import "./explore.css";
import "./userSearch.css";

const getHotScore = (journal) => {
    if(typeof journal?.hot_score === "number"){
        return journal.hot_score;
    }

    const likes = journal?.like_count?.[0]?.count || 0;
    const comments = journal?.comment_count?.[0]?.count || 0;
    const bookmarks = journal?.bookmark_count?.[0]?.count || 0;
    const views = journal?.views || 0;

    return (views * 6) + (likes * 3) + (comments * 2) + (bookmarks * 2);
};

const FlameIcon = ({ className }) => (
    <svg className={className} viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
        <path d="M12 2C10.97 6.5 6 9.5 6 14C6 17.31 8.69 20 12 20C15.31 20 18 17.31 18 14C18 9.5 13.03 6.5 12 2Z" fill="currentColor"/>
        <path d="M12 20C10.34 20 9 18.66 9 17C9 15 12 12 12 12C12 12 15 15 15 17C15 18.66 13.66 20 12 20Z" fill="var(--bg-card)" opacity="0.6"/>
    </svg>
);

const HeroCard = ({ journal, parsedContent, hotScore, onClick }) => (
    <motion.div
        className="explore-hero-wrap"
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
    >
        <div className="explore-hero-glow" />
        <div
            className="explore-hero-card"
            onClick={() => onClick(journal.id)}
            role="button"
            tabIndex={0}
            onKeyDown={(e) => {
                if(e.key === "Enter" || e.key === " "){
                    e.preventDefault();
                    onClick(journal.id);
                }
            }}
        >

        {parsedContent?.firstImage && (
            <div className="explore-hero-image-wrap">
                <img
                    className="explore-hero-image"
                    src={parsedContent.firstImage.src}
                    alt={journal?.title ? `${journal.title} cover image` : "Post cover image"}
                    loading="eager"
                    onError={handleImageFallback}
                />
                <div className="explore-hero-image-overlay" />
            </div>
        )}

        <div className={`explore-hero-body ${parsedContent?.firstImage ? "explore-hero-body--has-image" : ""}`}>
            <div className="explore-hero-badge">
                <FlameIcon className="explore-hero-flame" />
                <span className="explore-hero-badge-text">#1 Hottest</span>
            </div>

            <h2 className="explore-hero-title">
                {journal?.title?.length > 80 ? `${journal.title.substring(0, 80)}...` : (journal?.title || "Untitled")}
            </h2>

            <p className="explore-hero-excerpt">{parsedContent?.slicedText}</p>

            <div className="explore-hero-footer">
                <div className="explore-hero-author">
                    <div className={`user-avatar-container ${journal?.users?.badge === "legend" ? "avatar-ring-legend" : journal?.users?.badge === "og" ? "avatar-ring-og" : ""}`}>
                        <img
                            loading="lazy"
                            className="user-info-avatar"
                            src={journal?.users?.image_url || "/assets/profile.jpg"}
                            alt={`${journal?.users?.name || "User"} profile picture`}
