 1→export const ensureMeta = (id, attribute, key, content) => {
 2→  let element = document.getElementById(id);
 3→  if (!element) {
 4→    element = document.createElement("meta");
 5→    element.id = id;
 6→    document.head.appendChild(element);
 7→  }
 8→
 9→  element.setAttribute(attribute, key);
10→  element.setAttribute("content", content);
11→};
12→
13→export const removeElementById = (id) => {
14→  const element = document.getElementById(id);
15→  if (element && element.parentNode) {
16→    element.parentNode.removeChild(element);
17→  }
18→};
19→
20→export const ensureLink = (id, rel, href, extra = {}) => {
21→  let element = document.getElementById(id);
22→  if (!element) {
23→    element = document.createElement("link");
24→    element.id = id;
25→    document.head.appendChild(element);
26→  }
27→
28→  element.setAttribute("rel", rel);
29→  element.setAttribute("href", href);
30→  Object.entries(extra).forEach(([name, value]) => {
31→    element.setAttribute(name, value);
32→  });
33→};
34→
35→export const ensureJsonLd = (id, payload) => {
36→  let element = document.getElementById(id);
37→  if (!element) {
38→    element = document.createElement("script");
39→    element.id = id;
40→    element.type = "application/ld+json";
41→    document.head.appendChild(element);
42→  }
43→
44→  element.textContent = JSON.stringify(payload);
45→};
