1140→router.post('/update-username', requireAuth, async (req, res) => {
1141→    const userId = req.userId;
1142→    const { username } = req.body;
1143→
1144→    if (!username || typeof username !== 'string') {
1145→        return res.status(400).json({ error: 'username is required' });
1146→    }
1147→
1148→    const trimmed = username.trim();
1149→    if (trimmed.length < 3 || trimmed.length > 50) {
1150→        return res.status(400).json({ error: 'username must be 3-50 characters' });
1151→    }
1152→
1153→    if (!/^[a-zA-Z0-9-]+$/.test(trimmed)) {
1154→        return res.status(400).json({ error: 'username can only contain letters, numbers, and hyphens' });
1155→    }
1156→
1157→    const normalized = trimmed.toLowerCase();
1158→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
1159→    if (RESERVED_WORDS.includes(normalized)) {
1160→        return res.status(400).json({ error: 'this username is reserved' });
1161→    }
1162→
1163→    // Check uniqueness
1164→    const { data: existing } = await supabase
1165→        .from('users')
1166→        .select('id')
1167→        .ilike('username', normalized)
1168→        .neq('id', userId)
1169→        .limit(1);
1170→
1171→    if (existing && existing.length > 0) {
1172→        return res.status(409).json({ error: 'username is already taken' });
1173→    }
1174→
1175→    const { error: updateError } = await supabase
1176→        .from('users')
1177→        .update({ username: trimmed.toLowerCase() })
1178→        .eq('id', userId);
1179→
1180→    if (updateError) {
1181→        console.error('update-username error:', updateError.message);
1182→        return res.status(500).json({ error: 'failed to update username' });
1183→    }
1184→
1185→    return res.status(200).json({ message: 'success', username: trimmed.toLowerCase() });
1186→});
