 257→router.get('/getNotifications', requireAuth, async(req, res) =>{
 258→    const {before, limit} = req.query;
 259→    const userId = req.userId;
 260→
 261→    // Fetch a generous amount from both tables, then merge and paginate
 262→    const fetchLimit = parseInt(limit) + 1;
 263→
 264→    let journalQuery = supabase
 265→    .from('notifications')
 266→    .select(
 267→        `*,
 268→        journals!journal_id(title, content, created_at, likes(count), comments(count), bookmarks(count), users(name, id, image_url, badge)),
 269→        users!sender_id(name, user_email, image_url, id, badge),
 270→        constellation_id,
 271→        constellations!constellation_id(status, star_id_a, star_id_b)
 272→        `
 273→    )
 274→    .eq('receiver_id', userId)
 275→    .order('created_at', {ascending: false})
 276→    .order('id', {ascending: false})
 277→    .limit(fetchLimit)
 278→
 279→    let opinionQuery = supabase
 280→    .from('notification_opinions')
 281→    .select(
 282→        `*,
 283→        opinions!opinion_id(id, opinion, user_id, created_at, users(name, id, image_url, badge)),
 284→        users!sender_id(name, user_email, image_url, id, badge)
 285→        `
 286→    )
 287→    .eq('receiver_id', userId)
 288→    .order('created_at', {ascending: false})
 289→    .order('id', {ascending: false})
 290→    .limit(fetchLimit)
 291→
 292→    if(before){
 293→        journalQuery = journalQuery.lt('created_at', before);
 294→        opinionQuery = opinionQuery.lt('created_at', before);
 295→    }
 296→
 297→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 298→
 299→    if(journalResult.error){
 300→        console.error('error while fetching data from notification table:', journalResult.error);
 301→        return res.status(500).json({error: 'error fetching data from notification table'});
 302→    }
 303→    if(opinionResult.error){
 304→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 305→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 306→    }
 307→
 308→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 309→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 310→
 311→    // Merge and sort by created_at descending
 312→    const merged = [...journalNotifs, ...opinionNotifs]
 313→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 314→
 315→    // Likes/bookmarks lookup only for journal notifications
 316→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 317→
 318→    let hasLikedResult = [];
 319→    let hasBookMarkedResult = [];
 320→    if(journalIds.length > 0){
 321→        const [hasLiked, hasBookMarked] = await Promise.all([
 322→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 323→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 324→        ]);
 325→
 326→        if(hasLiked.error || hasBookMarked.error){
 327→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 328→        }
 329→        hasLikedResult = hasLiked.data || [];
 330→        hasBookMarkedResult = hasBookMarked.data || [];
 331→    }
 332→
 333→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 334→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 335→
 336→    const formatted = merged.map((notif) => ({
 337→        ...notif,
 338→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 339→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 340→    }))
 341→
 342→    const hasMore = formatted.length > parseInt(limit);
 343→    const slicedData = hasMore ? formatted.slice(0, parseInt(limit)) : formatted;
 344→
 345→    return res.status(200).json(
 346→        {
 347→            hasMore: hasMore,
 348→            data: slicedData,
 349→        }
 350→    )
 351→
 352→})
