153→            const first = doc.images.find((img) => imageFromNodeLike(img));
154→            if (first) image = imageFromNodeLike(first);
155→        }
156→
157→        return { text, image };
158→    } catch {
159→        return { text: '', image: null };
160→    }
161→};
