200→const resolveAbsoluteHttpUrl = (rawUrl) => {
201→    try {
202→        const raw = String(rawUrl || '').trim();
203→        if (!raw) return null;
204→
205→        const isSupabasePath =
206→            raw.startsWith('/storage/v1/object/public/')
207→            || raw.startsWith('storage/v1/object/public/');
208→
209→        const baseUrl = isSupabasePath && SUPABASE_URL
210→            ? `${SUPABASE_URL}/`
211→            : SITE_URL;
212→
213→        const parsed = new URL(raw, baseUrl);
214→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
215→            return null;
216→        }
217→        return parsed.toString();
218→    } catch {
219→        return null;
220→    }
221→};
222→
223→const isPrivateIpv4Address = (ip) => {
224→    const parts = ip.split('.').map((part) => Number(part));
225→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
226→        return true;
227→    }
228→
229→    const [a, b] = parts;
230→    if (a === 10 || a === 127 || a === 0) return true;
231→    if (a === 169 && b === 254) return true;
232→    if (a === 172 && b >= 16 && b <= 31) return true;
233→    if (a === 192 && b === 168) return true;
234→    return false;
235→};
236→
237→const isPrivateIpv6Address = (ip) => {
238→    const normalized = ip.toLowerCase();
239→    return (
240→        normalized === '::1' ||
241→        normalized.startsWith('fc') ||
242→        normalized.startsWith('fd') ||
243→        normalized.startsWith('fe80:')
244→    );
245→};
246→
247→const isPrivateIpAddress = (ip) => {
248→    const ipVersion = net.isIP(ip);
249→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
250→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
251→    return true;
252→};
253→
254→const isSafeRemoteImageUrl = (imageUrl) => {
255→    try {
256→        const parsed = new URL(imageUrl);
257→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
258→            return false;
259→        }
260→
261→        const hostname = parsed.hostname.toLowerCase();
262→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
263→            return false;
264→        }
265→
266→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
267→            return false;
268→        }
269→
270→        return true;
271→    } catch {
272→        return false;
273→    }
274→};
275→
276→const evaluateShareImageCandidate = (rawUrl) => {
277→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
278→    if (!absoluteUrl) {
279→        return {
280→            ok: false,
281→            reason: 'invalid_or_non_http_url',
282→            resolvedUrl: null,
283→        };
284→    }
285→
286→    let path = '';
287→    try {
288→        const parsed = new URL(absoluteUrl);
289→        path = String(parsed.pathname || '').toLowerCase();
290→    } catch {
291→        return {
292→            ok: false,
293→            reason: 'invalid_resolved_url',
294→            resolvedUrl: null,
295→        };
296→    }
297→
298→    if (path.endsWith('.svg')) {
299→        return {
300→            ok: false,
301→            reason: 'svg_not_supported_for_share_image',
302→            resolvedUrl: absoluteUrl,
303→        };
304→    }
305→
306→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
307→        return {
308→            ok: false,
309→            reason: 'unsafe_remote_url',
310→            resolvedUrl: absoluteUrl,
311→        };
312→    }
313→
314→    return {
315→        ok: true,
316→        reason: 'ok',
317→        resolvedUrl: absoluteUrl,
318→    };
319→};
320→
321→const fetchRemoteImageBuffer = async (imageUrl) => {
322→    const controller = new AbortController();
323→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
324→
325→    try {
326→        const response = await fetch(imageUrl, {
327→            method: 'GET',
328→            redirect: 'follow',
329→            signal: controller.signal,
330→            headers: {
331→                Accept: 'image/*,*/*;q=0.8',
332→                'Accept-Encoding': 'identity',
333→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
334→            },
335→        });
336→
337→        if (!response.ok) {
338→            throw new Error(`upstream image status ${response.status}`);
339→        }
340→
341→        const finalUrl = response.url || imageUrl;
342→        if (!isSafeRemoteImageUrl(finalUrl)) {
343→            throw new Error('upstream redirected to unsafe url');
344→        }
345→
346→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
347→        if (!contentType.startsWith('image/')) {
348→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
349→        }
350→        if (contentType.includes('image/svg')) {
351→            throw new Error('svg images are not used for share previews');
352→        }
353→
354→        const headerContentLength = Number(response.headers.get('content-length'));
355→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
356→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
357→        }
358→
359→        const arrayBuffer = await response.arrayBuffer();
360→        const buffer = Buffer.from(arrayBuffer);
361→
362→        if (!buffer.length) {
363→            throw new Error('upstream image is empty');
364→        }
365→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
366→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
367→        }
368→
369→        return {
370→            buffer,
371→            contentType,
372→            byteLength: buffer.length,
373→            finalUrl,
374→        };
375→    } finally {
376→        clearTimeout(timeout);
377→    }
378→};
379→
380→const convertToOgJpeg = async (inputBuffer) => {
381→    return sharp(inputBuffer, { limitInputPixels: 60_000_000 })
382→        .rotate()
383→        .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, {
384→            fit: 'contain',
385→            background: { r: 255, g: 255, b: 255, alpha: 1 },
386→        })
387→        .jpeg({ quality: 82, mozjpeg: true })
388→        .toBuffer();
389→};
